import React from 'react';
import { Text, Stack, Section, Image } from '@shopify/ui-extensions-react/point-of-sale';

const greenBox = "data:image/png;base64,"
const bluebox = "data:image/png;base64,"
const yellowBox = "data:image/png;base64,"
const redBox = "data:image/png;base64,"
const SDD = "data:image/png;base64,"
const purpleBox = "data:image/png;base64,";



const Bopis = "data:image/png;base64,"

const InStorePickup ="data:image/png;base64,"

const InstoreSTS= "data:image/png;base64,"
export const OrderCountCard = ({ count, type, color, deviceName, text,badge=0 }) => {

  const getBox = (boxcolor: string) => {
    switch (boxcolor) {
      case "green":
        return greenBox;
      case "blue":
        return bluebox;
      case "red":
        return redBox;
      case "yellow":
        return yellowBox;
      case "purple":
        return purpleBox;  
      case "SDD":
        return SDD;
      case "Bopis":
        return Bopis;
      case "InStorePickup" :
        return InStorePickup;
      case "InStoreSTS":
        return InstoreSTS;
    }
  }
  const getTextColor = (boxcolor: string) => {
    switch (boxcolor) {
      case "green":
        return "TextSuccess";
      case "blue":
        return "TextInteractive";
      case "red":
        return "TextCritical";
      case "yellow":
        return "TextWarning";
      case "purple":
        return "TextNeutral";  
      default:
        return "TextDefault"; // fallback if color is not matched
    }
  };

  return (

   <Section>
      <Stack direction="inline" justifyContent="center" alignContent='center' alignItems='center'>
        <Image src={getBox(color)} />
      </Stack>
      {/* <Icon name="orders" size="major" /> */}
      <Stack direction="block"  alignContent='center' alignItems='center' paddingBlock='100'>
        {count !== '' ? <Text variant={deviceName == 'iPad' ? "headingLarge" : "headingSmall"} color={getTextColor(color)}>{count} </Text> :
          <Text variant={deviceName == 'iPad' ? "headingLarge" : "headingSmall"} color={badge > 0?'TextCritical':'TextSuccess'}>{text} </Text>
        }
      </Stack>

      <Stack direction="block" alignContent='center' alignItems='center' paddingBlock='200'><Text variant="captionRegularTall" color={getTextColor(color)}>{type}</Text></Stack>
      </Section>
  );
}



